// ── EXTRACT ARTICLE CONTENT V5 (BẢN HOÀN CHỈNH) ──────────────────────

const items = [];
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.collected)) staticData.collected = [];

// 1. LẤY METADATA TỪ LOOP (Phòng hờ n8n mất data)
let originalItems = [];
try {
    originalItems = $items("Loop Over Items", 0, $runIndex);
} catch (e) {}

// Hàm dọn rác văn bản cơ bản
function clean(text) {
  return (text || "")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, " ")
    .trim();
}

let index = 0;
for (const item of $input.all()) {
  try {
    const html = item.json.data || item.json.html_data || "";

    // Bỏ qua nếu lỗi mạng hoặc cục HTML trống
    if (!html || html.length < 50 || item.json.statusCode >= 400) {
        index++; continue;
    }

    // 2. TRÍCH XUẤT THÔNG TIN CƠ BẢN (Quét 3 lớp chống mất data)
    const rss = originalItems[index] ? originalItems[index].json : {};

    const urlMatch = html.match(/<link[^>]*rel="canonical"[^>]*href="([^"]+)"/i) || [];
    const ogTitle = (html.match(/<meta[^>]*property="og:title"[^>]*content="([^"]+)"/i) || [])[1];
    const metaTitle = (html.match(/<title>([\s\S]*?)<\/title>/i) || [])[1];
    const metaAuthor = (html.match(/<meta[^>]*name="author"[^>]*content="([^"]+)"/i) || [])[1];
    const pubDateMatch = html.match(/<meta[^>]*property="article:published_time"[^>]*content="([^"]+)"/i) || [];

    const url = rss.link || rss.url || urlMatch[1] || item.json.url || "";

    let title = rss.title || ogTitle || metaTitle || item.json.title || "Không có tiêu đề";
    // Tự động gọt bỏ đuôi tên báo rườm rà trong Title
    title = clean(title).replace(/\s*-\s*(Báo\s+)?(VnExpress|Tuổi Trẻ|Thanh Niên|Dân Trí|VietNamNet|Sức khỏe).*/i, "");

    const author = clean(rss.creator || rss.author || metaAuthor || "Không rõ");
    const date = rss.isoDate || rss.pubDate || pubDateMatch[1] || "";

    // Gắn nguồn tự động nếu Node Tag đằng trước bị xịt
    let source = rss.source_name || item.json.source_name || "Unknown";
    if (source === "Unknown" && url) {
        if (url.includes("vnexpress.net")) source = "VnExpress Sức khỏe";
        else if (url.includes("tuoitre.vn")) source = "Tuổi Trẻ Sức khỏe";
        else if (url.includes("dantri.com.vn")) source = "Dân Trí Sức khỏe";
        else if (url.includes("vietnamnet.vn")) source = "VietNamNet Sức khỏe";
    }

    // 3. BỘ LỌC THÉP (Chém bay Quảng Cáo, Sidebar, Tin Nóng Showbiz)
    let text = html
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<nav[\s\S]*?<\/nav>/gi, '')
      .replace(/<footer[\s\S]*?<\/footer>/gi, '')
      .replace(/<header[\s\S]*?<\/header>/gi, '')
      .replace(/<aside[\s\S]*?<\/aside>/gi, '') 
      .replace(/<div[^>]*class="[^"]*(?:related-news|trending|hot-news)[^"]*"[^>]*>[\s\S]*?<\/div>/gi, '');

    // 4. VÉT CẠN ĐÁY (Lấy từ thẻ mở của thân bài cho đến cuối)
    let bodyHtml = "";
    const startMatch = 
      text.match(/<div[^>]*class="[^"]*singular-content[^"]*"[^>]*>([\s\S]*)/i) || // Dân Trí
      text.match(/<div[^>]*class="[^"]*maincontent[^"]*"[^>]*>([\s\S]*)/i) ||      // VietNamNet
      text.match(/<div[^>]*class="[^"]*detail-content[^"]*"[^>]*>([\s\S]*)/i) ||   // Class chung
      text.match(/<div[^>]*id="main-detail"[^>]*>([\s\S]*)/i) ||                   // Tuổi Trẻ
      text.match(/<div[^>]*class="[^"]*e-magazine-content[^"]*"[^>]*>([\s\S]*)/i) || // Dân Trí
      text.match(/<article[^>]*>([\s\S]*)/i);                                      // VnExpress

    // Nếu tìm thấy cấu trúc báo chuẩn thì lấy, không thì lấy toàn bộ text đã dọn rác
    if (startMatch) {
        bodyHtml = startMatch[1];
    } else {
        bodyHtml = text; 
    }

    const content = clean(bodyHtml);

    // 5. ĐIỀU KIỆN LƯU BÀI (Bài phải dài trên 150 ký tự)
    if (content.length >= 150) {
        const article = { 
            source, 
            title, 
            content, 
            author, 
            published_at: date, 
            url, 
            crawled_at: new Date().toISOString() 
        };
        items.push({ json: article });
        staticData.collected.push(article);
    }
  } catch (err) {
    console.log(`[Extract] Lỗi bài: ${err.message}`);
  }
  index++;
}

// 6. ĐỐT RÁC RAM (Chống lỗi 503 Out Of Memory của n8n)
$input.all().forEach(i => { delete i.json.data; delete i.json.html_data; });

// Trả về kết quả, nếu mẻ này toàn bài lỗi thì trả dummy item để Loop không bị sập
return items.length > 0 ? items : [{ json: { _bad_batch: true } }];

// ── DEDUPLICATE & MERGE ──────────────────────────────────────────────
// Đọc bài đã gom từ tất cả batch (qua staticData.collected).
// So với kho bài cũ (staticData.articles), lọc trùng theo URL.
// Lưu kết quả lại vào staticData.articles cho lần chạy sau.
// Clear staticData.collected để lần chạy tiếp theo bắt đầu sạch.

const staticData = $getWorkflowStaticData('global');

const newArticlesAll = staticData.collected || [];
const existing       = staticData.articles   || [];

const seenUrls   = new Set(existing.map(a => a.url));
const newArticles = newArticlesAll.filter(a => a.url && !seenUrls.has(a.url));

// Giữ tối đa 2000 bài, ưu tiên bài mới nhất
const merged = [...existing, ...newArticles].slice(-2000);

// Lưu lại
staticData.articles  = merged;
staticData.collected = []; // reset cho execution tiếp theo

console.log(`[Dedup] +${newArticles.length} mới | ${existing.length} cũ | tổng ${merged.length}`);

// Output JSON + Binary (để Save node ghi file)
const jsonStr = JSON.stringify(merged, null, 2);

return [{
  json: { articles: merged, new_count: newArticles.length },
  binary: {
    articlesFile: {
      data:          Buffer.from(jsonStr).toString('base64'),
      mimeType:      'application/json',
      fileName:      'articles.json',
      fileExtension: 'json'
    }
  }
}];

// ── PREPARE INGEST PAYLOAD ───────────────────────────────────────────
// Chỉ gửi bài MỚI lên RAG server, không gửi lại toàn bộ kho.

const data        = $input.first().json;
const allArticles = data.articles   || [];
const newCount    = data.new_count  || 0;

const newArticles = newCount > 0 ? allArticles.slice(-newCount) : [];

console.log(`[Payload] Chuẩn bị gửi ${newArticles.length} bài mới lên RAG server`);

return [{ json: { articles: newArticles } }];

// ── LOG RESULT ───────────────────────────────────────────────────────
const res = $input.first().json;

const ingested = res.total_ingested ?? 0;
const skipped  = res.total_skipped  ?? 0;
const errors   = res.errors?.length ?? 0;

const msg = `✅ RAG Ingest xong: ${ingested} bài mới vào DB | ${skipped} trùng bỏ qua | ${errors} lỗi`;
console.log(msg);

return [{ json: { status: 'done', ingested, skipped, errors, message: msg } }];
